+    let mut total = 0;
+    if layer_idx > 0 {
+        total += count_crossings_pair(&layers[layer_idx - 1], &layers[layer_idx], adj);
+    }
+    if layer_idx + 1 < layers.len() {
+        total += count_crossings_pair(&layers[layer_idx], &layers[layer_idx + 1], adj);
+    }
+    total
+}
